'use strict';

const fs = require('fs');
const path = require('path');

const ROOT = path.resolve(__dirname, '..');
const PUBLIC_DIR = path.join(ROOT, 'public');
const CLIENT_VERSION = 'v0.71.13';

const CLIENT_SCRIPT_PARTS = [
  '00-core-state.js',
  '01-startup-events-auth.js',
  '02-tutorial-layout-overview.js',
  '03-research-lines-foundations.js',
  '04-lines.js',
  '05-fleet-compositions.js',
  '06-stations-staff-research.js',
  '07-resources-budget-market.js',
  '08-actions-modals.js',
  '09-map-rendering.js',
  '10-routing-line-utils.js'
];

const CLIENT_STYLE_PARTS = [
  '00-base-layout.css',
  '01-theme-map-ui.css',
  '02-lines-fleet-research.css',
  '03-accounts-budget-admin.css',
  '04-compositions.css',
  '05-bugs-research-overview.css'
];

function readParts(dir, names, commentType) {
  return names.map(name => {
    const comment = commentType === 'css'
      ? `/* ===== ${name} ===== */`
      : `// ===== ${name} =====`;
    return `${comment}\n${fs.readFileSync(path.join(dir, name), 'utf8')}`;
  }).join('\n\n');
}

const appBundle = [
  "'use strict';",
  "function showSillonsClientBootError(error) {",
  "  console.error(error);",
  "  const host = document.getElementById('toastHost') || document.body;",
  "  const div = document.createElement('div');",
  "  div.className = 'toast bad';",
  "  div.textContent = 'Erreur de chargement du client Sillons.';",
  "  host.appendChild(div);",
  "}",
  "window.__sillonsClientBootError = showSillonsClientBootError;",
  readParts(path.join(PUBLIC_DIR, 'js'), CLIENT_SCRIPT_PARTS, 'js'),
  "if (typeof init === 'function') Promise.resolve(init()).catch(showSillonsClientBootError);",
  "else showSillonsClientBootError(new Error('Initialisation client absente.'));"
].join('\n\n');

const styles = [
  `/* Sillons static CSS bundle - ${CLIENT_VERSION}. Generated by scripts/build-static-bundles.js. */`,
  readParts(path.join(PUBLIC_DIR, 'css'), CLIENT_STYLE_PARTS, 'css')
].join('\n\n');

fs.writeFileSync(path.join(PUBLIC_DIR, 'app.js'), `${appBundle.trimEnd()}\n`, 'utf8');
fs.writeFileSync(path.join(PUBLIC_DIR, 'styles.css'), `${styles.trimEnd()}\n`, 'utf8');

console.log(`Built public/app.js and public/styles.css for ${CLIENT_VERSION}.`);
